import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const mockClearActiveStudioSession = vi.fn();
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
const mockCloseStudio = vi.fn().mockResolvedValue({ ok: true });
// biome-ignore lint/suspicious/noExplicitAny: test capture of the poll opts
let capturedPollOpts = null;
const mockPollAgentSessionEvents = vi.fn((...args) => {
    capturedPollOpts = args[0];
    // Never resolves on its own; the test drives onEvent manually.
    return new Promise(() => { });
});
vi.mock("../activeStudioSession.js", () => ({
    clearActiveStudioSession: (...args) => mockClearActiveStudioSession(...args),
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
}));
const mockFetchStreamTip = vi.fn().mockResolvedValue("200-5");
vi.mock("../agentSessionChannel.js", () => ({
    closeStudio: (...args) => mockCloseStudio(...args),
    fetchStreamTip: (...args) => mockFetchStreamTip(...args),
    pollAgentSessionEvents: (...args) => mockPollAgentSessionEvents(...args),
}));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: "test-key" }),
    hasCredentials: () => true,
}));
const SESSION = "11111111-1111-4111-8111-111111111111";
const KILL_DELAY_MS = 2_500;
const CONFIRM_TIMEOUT_MS = 8_000;
const GRACE_MS = 10_000;
describe("runCloseStudio", () => {
    let exitMock;
    let killMock;
    let savedArgv;
    beforeEach(() => {
        capturedPollOpts = null;
        mockClearActiveStudioSession.mockClear();
        mockReadActiveStudioSession.mockReset().mockReturnValue(null);
        mockCloseStudio.mockClear();
        vi.stubGlobal("fetch", vi.fn().mockResolvedValue({
            ok: true,
            json: async () => ({ events: [{ id: "100-0" }, { id: "200-5" }] }),
        }));
        exitMock = vi
            .spyOn(process, "exit")
            .mockImplementation((() => undefined));
        killMock = vi
            .spyOn(process, "kill")
            .mockImplementation((() => true));
        savedArgv = process.argv;
        process.argv = ["node", "closeStudio.js", SESSION];
    });
    afterEach(() => {
        process.argv = savedArgv;
        exitMock.mockRestore();
        killMock.mockRestore();
        vi.unstubAllGlobals();
    });
    it("polls from the stream tip and clears only on a window-closed that survives the grace", async () => {
        vi.useFakeTimers();
        try {
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            // Flush microtasks (no clock advance) so the poll has started.
            await vi.advanceTimersByTimeAsync(0);
            // The load-bearing assertion: the poll starts AFTER the pre-close tip,
            // so any window-closed already in history (id <= tip) is never seen.
            expect(capturedPollOpts.startCursor).toBe("200-5");
            expect(mockCloseStudio).toHaveBeenCalled();
            // A fresh window-closed (produced by our own close) is the only
            // confirmation candidate; session-ended/session-closed are ignored.
            capturedPollOpts.onEvent({ type: "studio:session-ended", data: {} });
            capturedPollOpts.onEvent({ type: "studio:session-closed", data: {} });
            capturedPollOpts.onEvent({ type: "studio:window-closed", data: {} });
            // Not proof yet: a reload could still refute it within the grace.
            await vi.advanceTimersByTimeAsync(GRACE_MS - 1);
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(2);
            await run;
            expect(mockClearActiveStudioSession).toHaveBeenCalledWith(SESSION, {
                force: true,
            });
            // The kill fallback fired mid-grace but no-ops without a matching
            // pointer record (mockReadActiveStudioSession returns null here).
            expect(killMock).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("does NOT clear when the window-closed was a refresh (session-started refutes it)", async () => {
        vi.useFakeTimers();
        try {
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedPollOpts).not.toBeNull();
            // The user refreshed during the close window: window-closed then the
            // reload's session-started. The candidate is refuted; with no further
            // confirmation the deadline passes and the pointer is kept.
            capturedPollOpts.onEvent({ type: "studio:window-closed", data: {} });
            capturedPollOpts.onEvent({ type: "studio:session-started", data: {} });
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS + GRACE_MS + 1);
            await run;
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("SIGTERMs the recorded window pid when no confirmation arrives, and keeps the pointer", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: SESSION,
                serviceUrl: "https://test.invalid",
                pid: 123,
                startedAt: "2026-01-01T00:00:00.000Z",
                windowPid: 4242,
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            // Flush microtasks (no clock advance — vi.waitFor would advance the
            // fake clock and fire the very timers under test) so the poll has
            // started and the kill-delay timer exists.
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedPollOpts).not.toBeNull();
            expect(mockCloseStudio).toHaveBeenCalled();
            // The web's own window.close() gets a head start before the kill.
            await vi.advanceTimersByTimeAsync(KILL_DELAY_MS - 1);
            expect(killMock).not.toHaveBeenCalled();
            await vi.advanceTimersByTimeAsync(2);
            expect(killMock).toHaveBeenCalledWith(4242, "SIGTERM");
            // Still no window-closed by the timeout: the window may be alive, so
            // the pointer is kept (trying is not proof).
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS);
            await run;
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("does not kill when the pointer belongs to a different session or has no pid", async () => {
        vi.useFakeTimers();
        try {
            mockReadActiveStudioSession.mockReturnValue({
                sessionId: "22222222-2222-4222-8222-222222222222",
                serviceUrl: "https://test.invalid",
                pid: 123,
                startedAt: "2026-01-01T00:00:00.000Z",
                windowPid: 4242,
            });
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            // Flush microtasks (no clock advance) so the kill-delay timer exists,
            // then walk through the kill fallback (which must no-op on the session
            // mismatch) and the confirmation timeout.
            await vi.advanceTimersByTimeAsync(0);
            expect(capturedPollOpts).not.toBeNull();
            await vi.advanceTimersByTimeAsync(KILL_DELAY_MS + 1);
            await vi.advanceTimersByTimeAsync(CONFIRM_TIMEOUT_MS);
            await run;
            expect(killMock).not.toHaveBeenCalled();
            expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        }
        finally {
            vi.useRealTimers();
        }
    });
    it("exits quietly when the close push fails (session already gone)", async () => {
        mockCloseStudio.mockRejectedValueOnce(new Error("403"));
        // Make the mocked exit actually stop the flow (the real one never returns).
        exitMock.mockImplementation(((code) => {
            throw new Error(`exit:${code}`);
        }));
        const { runCloseStudio } = await import("./closeStudio.js");
        await expect(runCloseStudio()).rejects.toThrow("exit:0");
        expect(mockClearActiveStudioSession).not.toHaveBeenCalled();
        expect(killMock).not.toHaveBeenCalled();
    });
});
